需要严格递增序列 二分查找 不确定有无的寻找 int binary_search(int arr[], int n, int left, int right)
{ int mid = left + (right - left) / 2; while (left <= right) { mid = left + (right - left) / 2; if (arr[mid] == n) { return mid; } else if (arr[mid] > n) { right = mid -1; } else { left = mid + 1; } } return -1;
} 寻找第一个大于等于的 int lowerbound(int A[], int x, int left, int right)
{ int mid; while (left < right) { mid = left + (right - left) / 2; if (A[mid] >= x) { right = mid; } else { left = mid + 1; } } return left;
} 寻找第一个大于的 int upperbound(int A[], int x, int left, int right)
{ int mid; while (left < right) { mid = left + (right - left) / 2; if (A[mid] > x) { right = mid; } else { left = mid + 1; } } return left;
} 二分夹逼 快速幂 typedef long long LL
LL binaryPow(LL a, LL b, LL m)
{ if (b == 0) return 1; if (b % 2 == 1) return a * binaryPow(a, b -1, m) % m; else { LL mu1 = binaryPow(a, b / 2, m) { return mu1 * mu1 % m; } }
} 迭代写法 typedef long long LL
LL binaryPow(LL a, LL b, LL m)
{ LL ans = 1; while (b > 0) { if (b > 0) { if (b & 1) { ans = ans * a % m; } a = a * a % m; b >>= 1; } } return ans;
}

